// Generated by Cypress Author — 2026-05-26
// Covers: HrZonesChart + AIInsightCard on the Activity Detail page
//   /main/running/activities/:id
//
// HrZonesChart states:
//   - empty state when activity has no zone data
//   - Z1-Z5 rows with label, HR range, percentage, duration when data present
//   - always renders section root (hrZonesSection)
//
// AIInsightCard states:
//   - loading skeleton while insight fetch is in-flight
//   - empty state with focus buttons when no insight exists (null response)
//   - generate → pending state when POST succeeds
//   - content state when insight is completed + is_valid + has content
//   - error state with retry when GET insight fetch fails
//   - completed + invalid falls back to empty/focus-button state

import constants from '../../../fixtures/app-constants.json'

const IDS = constants.test_ids.running_activity_detail
const ACTIVITY_ID = 'test-activity-id-hrzones-ai'
const DETAIL_URL = `/main/running/activities/${ACTIVITY_ID}`
const AI_EP = constants.endpoints.running_ai_insights.list
const AI_GEN_EP = constants.endpoints.running_ai_insights.generate

// ---------------------------------------------------------------------------
// Shared fixtures
// ---------------------------------------------------------------------------

const baseActivity = {
  id: ACTIVITY_ID,
  name: 'Long Run with Zones',
  activity_type: 'Run',
  source: 'strava',
  started_at: '2026-05-26T06:00:00Z',
  distance_m: 15000,
  moving_time_sec: 5400,
  duration_sec: 5460,
  avg_pace_sec_per_km: 360,
  avg_hr: 148,
  max_hr: 172,
  avg_cadence: 83,
  elevation_gain_m: 80,
  calories: 900,
  pr_count: 0,
  workout_type: null,
  summary_polyline: null,
  gear: null,
  device_name: null,
  notes: null,
  weather_summary: null,
  zones: null,
}

const hrZonesData = {
  heart_rate: {
    zones: [
      { min: 0, max: 114, time: 600 }, // Z1 Recovery
      { min: 115, max: 152, time: 1800 }, // Z2 Aerobic
      { min: 153, max: 171, time: 2100 }, // Z3 Tempo
      { min: 172, max: 190, time: 600 }, // Z4 Threshold
      { min: 191, max: 220, time: 300 }, // Z5 VO2max
    ],
  },
}

const dashboardFixture = {
  training_load: { next_race_goal: null },
  weekly_stats: null,
  ytd_stats: null,
  recent_activities: [],
  health_checkin: null,
}

// ---------------------------------------------------------------------------
// Shared stubs — reused across all describe blocks
// ---------------------------------------------------------------------------

const stubRtUsers = () => {
  cy.intercept('GET', '**/rest/v1/rt_users*', {
    statusCode: 200,
    body: [{ id: 'test-user-id', onboarding_complete: true }],
  }).as('rtUsersCheck')
}

const stubActivity = (overrides = {}) => {
  cy.intercept('GET', `/api/running/v1/activities/${ACTIVITY_ID}`, {
    statusCode: 200,
    body: {
      activity: { ...baseActivity, ...overrides },
      splits: [],
      laps: [],
      best_efforts: [],
      photos: [],
    },
  }).as('getActivity')
}

const stubDashboard = () => {
  cy.intercept('GET', '/api/running/v1/dashboard', {
    statusCode: 200,
    body: { data: dashboardFixture },
  }).as('getDashboard')
}

const stubRaceLog = () => {
  cy.intercept('GET', '/api/running/v1/race-log*', {
    statusCode: 200,
    body: { data: [] },
  }).as('getRaceLog')
}

const stubStreams = () => {
  cy.intercept('GET', `/api/running/v1/activities/*/streams*`, {
    statusCode: 200,
    body: {
      meta: {
        has_hr: false,
        has_cadence: false,
        has_altitude: false,
        total_points: 0,
        returned_points: 0,
        resolution: '10s',
      },
      data: [],
    },
  }).as('getStreams')
}

const stubInsight = (body, statusCode = 200) => {
  // fetchActivityInsight always calls res.json() and returns data.data?.[0] ?? null
  // For "no insight" pass { statusCode: 200, body: { data: [] } }
  // For a real insight pass { statusCode: 200, body: { data: [insightObj] } }
  // For fetch error pass a non-2xx statusCode with an error body
  cy.intercept('GET', `${AI_EP}*`, { statusCode, body }).as('getInsight')
}

const visitAndWait = () => {
  cy.viewport(1280, 720)
  cy.visit(DETAIL_URL)
  cy.wait('@getActivity')
}

// ---------------------------------------------------------------------------
// A. Auth guard
// ---------------------------------------------------------------------------

describe('Activity Detail (HR Zones + AI Insight) — Auth guard', () => {
  it('unauthenticated visit redirects to /login', () => {
    cy.clearAllCookies()
    cy.clearAllLocalStorage()
    cy.visit(DETAIL_URL, { failOnStatusCode: false })
    cy.url().should('include', '/login')
  })
})

// ---------------------------------------------------------------------------
// B. HrZonesChart — empty state (no zone data)
// ---------------------------------------------------------------------------

describe('HrZonesChart — empty state when no zone data', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    // Activity with zones: null (default)
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ data: [] })
    visitAndWait()
  })

  it('hrZonesSection is always rendered', () => {
    cy.get(`#${IDS.hr_zones_section}`).should('exist')
  })

  it('shows "Zone data not available" when activity.zones is null', () => {
    cy.get(`#${IDS.hr_zones_empty}`).should('exist').and('contain.text', 'Zone data not available')
  })

  it('does not render zone bar rows when zones is null', () => {
    // No percentage text should appear in the section
    cy.get(`#${IDS.hr_zones_section}`).should('not.contain.text', '%')
  })
})

// ---------------------------------------------------------------------------
// C. HrZonesChart — happy path (Z1-Z5 data present)
// ---------------------------------------------------------------------------

describe('HrZonesChart — renders Z1-Z5 rows when zone data is present', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity({ zones: hrZonesData })
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ data: [] })
    visitAndWait()
  })

  it('does not show empty state when zones are present', () => {
    cy.get(`#${IDS.hr_zones_empty}`).should('not.exist')
  })

  it('renders 5 zone rows', () => {
    // Each zone row has a label like "Z1 Recovery", "Z2 Aerobic", etc.
    cy.get(`#${IDS.hr_zones_section}`).within(() => {
      cy.contains('Z1 Recovery').should('exist')
      cy.contains('Z2 Aerobic').should('exist')
      cy.contains('Z3 Tempo').should('exist')
      cy.contains('Z4 Threshold').should('exist')
      cy.contains('Z5 VO2max').should('exist')
    })
  })

  it('renders HR range labels for each zone', () => {
    cy.get(`#${IDS.hr_zones_section}`).within(() => {
      // Z1 should say "< 114 bpm" and Z5 "> 191 bpm"
      cy.contains('< 114 bpm').should('exist')
      cy.contains('> 191 bpm').should('exist')
      cy.contains('115–152 bpm').should('exist')
    })
  })

  it('renders percentage and duration for each zone', () => {
    // Total time = 600+1800+2100+600+300 = 5400
    // Z2: 1800/5400 = 33%
    cy.get(`#${IDS.hr_zones_section}`).within(() => {
      cy.contains('33%').should('exist')
      // Z3: 2100/5400 = 39%
      cy.contains('39%').should('exist')
    })
  })

  it('renders a filled bar for each zone (has style with backgroundColor)', () => {
    cy.get(`#${IDS.hr_zones_section}`).within(() => {
      // Each zone bar has an inline backgroundColor style
      cy.get('div[style*="background-color"]').should('have.length', 5)
    })
  })
})

// ---------------------------------------------------------------------------
// D. AIInsightCard — loading state
// ---------------------------------------------------------------------------

describe('AIInsightCard — loading skeleton while fetch is in-flight', () => {
  it('shows loading skeleton before insight fetch resolves', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()

    // Delay insight response to catch loading state before fetch resolves
    cy.intercept('GET', `${AI_EP}*`, (req) => {
      req.reply((res) => {
        res.setDelay(600)
        res.send({ statusCode: 200, body: { data: [] } })
      })
    }).as('getInsightDelayed')

    cy.viewport(1280, 720)
    cy.visit(DETAIL_URL)
    cy.wait('@getActivity')

    cy.get(`#${IDS.ai_insight_card}`).should('exist')
    cy.get(`#${IDS.ai_insight_loading}`).should('exist')
  })
})

