// ---------------------------------------------------------------------------
// H. AIInsightCard — error state when fetch fails
// ---------------------------------------------------------------------------

describe('AIInsightCard — error state when GET insight fetch fails', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubActivity()
    stubDashboard()
    stubRaceLog()
    stubStreams()
    stubInsight({ error: 'Internal server error' }, 500)
    // 500 causes res.json() to throw after !res.ok check → loadError=true in component
    visitAndWait()
    cy.wait('@getInsight')
  })

  it('shows aiInsightError state after a fetch failure', () => {
    cy.get(`#${IDS.ai_insight_error}`).should('exist')
    cy.get(`#${IDS.ai_insight_error}`).within(() => {
      // Text changed in v1.2 from "Failed to load" to "Could not load analysis."
      cy.contains('Could not load analysis').should('exist')
    })
  })

  it('shows a retry button in the error state', () => {
    cy.get(`#${IDS.ai_insight_retry}`).scrollIntoView().should('be.visible')
  })

  it('clicking retry re-fetches and shows empty state on null response', () => {
    // Stub success BEFORE clicking so the intercept is in place when the request fires
    cy.intercept('GET', `${AI_EP}*`, { statusCode: 200, body: { data: [] } }).as('getInsightRetry')

    cy.get(`#${IDS.ai_insight_retry}`).click()
    cy.wait('@getInsightRetry')

    cy.get(`#${IDS.ai_insight_empty}`).should('be.visible')
    cy.get(`#${IDS.ai_insight_error}`).should('not.exist')
  })
})

